INSERT INTO `book_page` (`id`, `book_id`, `page_no`, `title`, `content_type`, `content_text_ko`, `content_text_en`, `image_url`, `created_at`, `updated_at`) VALUES
(2058, 186, 1, '작은 약속', 'ESSAY', '바람이 불어올 때마다 종소리가 은은하게 울렸습니다. 다락방에 쌓인 먼지 속에서 오래된 이야기가 깨어났습니다.', 'Every small step slowly grew into real courage. Every small step slowly grew into real courage.', NULL, '2026-07-20 20:51:00', '2026-07-20 20:51:00'),
(2059, 186, 2, '마지막 인사', 'ESSAY', '작은 발걸음 하나하나가 커다란 용기로 이어졌습니다. 다락방에 쌓인 먼지 속에서 오래된 이야기가 깨어났습니다.', 'Dust settled over the attic, and an old story quietly woke up. The bookshop owner carefully handed over a worn, old book.', NULL, '2026-07-20 20:51:00', '2026-07-20 20:51:00'),
(2060, 186, 3, '돌아오는 길', 'ESSAY', '창밖으로 노을이 번지자 마을 전체가 붉게 물들었습니다. 비 갠 뒤 하늘에는 두 개의 무지개가 나란히 걸렸습니다.', 'She ended the day listening to the slow turn of the water mill. Every small step slowly grew into real courage.', NULL, '2026-07-20 20:51:00', '2026-07-20 20:51:00'),
(2061, 186, 4, '마지막 인사', 'ESSAY', '작은 발걸음 하나하나가 커다란 용기로 이어졌습니다. 물레방아가 돌아가는 소리를 들으며 하루를 마무리했습니다.', 'At the end of the unfamiliar alley, an unexpected friend was waiting. The bookshop owner carefully handed over a worn, old book.', NULL, '2026-07-20 20:51:00', '2026-07-20 20:51:00'),
(2062, 186, 5, '숨겨진 편지', 'ESSAY', '책방 주인은 낡은 책 한 권을 조심스레 건네주었습니다. 바람이 불어올 때마다 종소리가 은은하게 울렸습니다.', 'Every small step slowly grew into real courage. The sunset spilled through the window, painting the whole village red.', NULL, '2026-07-20 20:51:00', '2026-07-20 20:51:00'),
(2063, 186, 6, '다시 부는 바람', 'ESSAY', '낯선 골목 끝에서 뜻밖의 친구를 만났습니다. 작은 발걸음 하나하나가 커다란 용기로 이어졌습니다.', 'Each time the wind blew, a bell rang softly in the distance. Every small step slowly grew into real courage.', NULL, '2026-07-20 20:51:00', '2026-07-20 20:51:00'),
(2064, 186, 7, '마지막 인사', 'ESSAY', '낯선 골목 끝에서 뜻밖의 친구를 만났습니다. 비 갠 뒤 하늘에는 두 개의 무지개가 나란히 걸렸습니다.', 'Dust settled over the attic, and an old story quietly woke up. Inside the old mailbox sat a letter that was never sent.', NULL, '2026-07-20 20:51:00', '2026-07-20 20:51:00'),
(2065, 187, 1, '다시 부는 바람', 'PAGE', NULL, NULL, 'https://picsum.photos/seed/page2065/800/600', '2026-07-20 15:24:00', '2026-07-20 15:24:00'),
(2066, 187, 2, '다시 부는 바람', 'PAGE', '다락방에 쌓인 먼지 속에서 오래된 이야기가 깨어났습니다. 창밖으로 노을이 번지자 마을 전체가 붉게 물들었습니다.', 'Each time the wind blew, a bell rang softly in the distance. The sunset spilled through the window, painting the whole village red.', NULL, '2026-07-20 15:24:00', '2026-07-20 15:24:00'),
(2067, 187, 3, '숨겨진 편지', 'PAGE', NULL, NULL, 'https://picsum.photos/seed/page2067/800/600', '2026-07-20 15:24:00', '2026-07-20 15:24:00'),
(2068, 187, 4, '숨겨진 편지', 'PAGE', '기차가 지나갈 때마다 작은 마을은 잠시 멈춘 듯했습니다. 낯선 골목 끝에서 뜻밖의 친구를 만났습니다.', 'Every small step slowly grew into real courage. Each time the wind blew, a bell rang softly in the distance.', NULL, '2026-07-20 15:24:00', '2026-07-20 15:24:00'),
(2069, 187, 5, '숨겨진 편지', 'PAGE', NULL, NULL, 'https://picsum.photos/seed/page2069/800/600', '2026-07-20 15:24:00', '2026-07-20 15:24:00'),
(2070, 187, 6, '숨겨진 편지', 'PAGE', '바람이 불어올 때마다 종소리가 은은하게 울렸습니다. 비 갠 뒤 하늘에는 두 개의 무지개가 나란히 걸렸습니다.', 'Whenever the train passed, the little town seemed to pause for a moment. After the rain, two rainbows stood side by side in the sky.', NULL, '2026-07-20 15:24:00', '2026-07-20 15:24:00'),
(2071, 187, 7, '작은 약속', 'PAGE', NULL, NULL, 'https://picsum.photos/seed/page2071/800/600', '2026-07-20 15:24:00', '2026-07-20 15:24:00'),
(2072, 187, 8, '작은 약속', 'PAGE', '낯선 골목 끝에서 뜻밖의 친구를 만났습니다. 오래된 우체통 속에는 아직 부치지 못한 편지가 남아 있었습니다.', 'Each time the wind blew, a bell rang softly in the distance. She ended the day listening to the slow turn of the water mill.', NULL, '2026-07-20 15:24:00', '2026-07-20 15:24:00'),
(2073, 187, 9, '돌아오는 길', 'PAGE', NULL, NULL, 'https://picsum.photos/seed/page2073/800/600', '2026-07-20 15:24:00', '2026-07-20 15:24:00'),
